Author: Tolyan Korniltsev <anatoly.korniltsev@grafana.com>
Date:   Fri May 8 14:59:08 2026 +1000

    fix: get_mach_cpu_type do not mutate imutable variable with raw pointers (#849)
---
 src/binary_parser.rs | 8 ++++----
 1 file changed, 4 insertions(+), 4 deletions(-)

diff --git a/src/binary_parser.rs b/src/binary_parser.rs
index a289137..0e889e3 100644
--- a/src/binary_parser.rs
+++ b/src/binary_parser.rs
@@ -29,14 +29,14 @@ impl BinaryInfo {

 #[cfg(target_os = "macos")]
 fn get_mach_cpu_type() -> goblin::mach::cputype::CpuType {
-    let is_arm: i32 = 0;
-    let size: usize = std::mem::size_of_val(&is_arm);
+    let mut is_arm: i32 = 0;
+    let mut size: libc::size_t = size_of_val(&is_arm);
     unsafe {
         let name = std::ffi::CString::new("hw.optional.arm64").expect("CString::new failed");
         let ret = libc::sysctlbyname(
             name.as_ptr() as *const i8,
-            &is_arm as *const _ as *mut _,
-            &size as *const _ as *mut _,
+            &mut is_arm as *mut _ as *mut libc::c_void,
+            &mut size,
             std::ptr::null_mut(),
             0,
         );

commit 7819d0662960c5a31cc927d1bd6b2014e08432f7
Author: Jake Kramer <899428+jake-kramer@users.noreply.github.com>
Date:   Fri May 1 10:02:36 2026 -0400

    feat: Format function names with qualname for Python 3.11+ (#825)

    This change will update function names to have module paths in them
    which is useful for disambiguating functions when viewing a profile.

    See https://docs.python.org/3/glossary.html#term-qualified-name
---
 src/python_interpreters.rs | 30 ++++++++++++++++++++++++++++++
 src/stack_trace.rs         | 10 +++++++++-
 2 files changed, 39 insertions(+), 1 deletion(-)

diff --git a/src/python_interpreters.rs b/src/python_interpreters.rs
index a08e639..66b618d 100644
--- a/src/python_interpreters.rs
+++ b/src/python_interpreters.rs
@@ -70,6 +70,12 @@ pub trait CodeObject: Copy {
     fn varnames(&self) -> *mut Self::TupleObject;

     fn get_line_number(&self, lasti: i32, table: &[u8]) -> i32;
+
+    /// Returns the qualified name (co_qualname) if available (Python 3.11+).
+    /// For older Python versions, returns None.
+    fn qualname(&self) -> Option<*mut Self::StringObject> {
+        None
+    }
 }

 pub trait BytesObject: Copy {
@@ -354,6 +360,10 @@ macro_rules! CompactCodeObjectImpl {
                 }
                 line_number
             }
+
+            fn qualname(&self) -> Option<*mut Self::StringObject> {
+                Some(self.co_qualname as *mut Self::StringObject)
+            }
         }
     };
 }
@@ -921,4 +931,24 @@ mod tests {
         ];
         assert_eq!(code.get_line_number(214, &table), 5);
     }
+
+    #[test]
+    fn test_py3_11_qualname() {
+        use crate::python_bindings::v3_11_0::PyCodeObject;
+        let code = PyCodeObject {
+            co_firstlineno: 1,
+            ..Default::default()
+        };
+        assert!(code.qualname().is_some());
+    }
+
+    #[test]
+    fn test_py3_10_qualname_not_available() {
+        use crate::python_bindings::v3_10_0::PyCodeObject;
+        let code = PyCodeObject {
+            co_firstlineno: 1,
+            ..Default::default()
+        };
+        assert!(code.qualname().is_none());
+    }
 }
diff --git a/src/stack_trace.rs b/src/stack_trace.rs
index b7fc404..cfdbb67 100644
--- a/src/stack_trace.rs
+++ b/src/stack_trace.rs
@@ -150,7 +150,15 @@ where
             .context("Failed to copy PyCodeObject")?;

         let filename = copy_string(code.filename(), process).context("Failed to copy filename");
-        let name = copy_string(code.name(), process).context("Failed to copy function name");
+
+        // Try to get qualname first (available in Python 3.11+), fall back to name
+        let name = match code.qualname() {
+            Some(qualname_ptr) => {
+                copy_string(qualname_ptr, process).or_else(|_| copy_string(code.name(), process))
+            }
+            None => copy_string(code.name(), process),
+        }
+        .context("Failed to copy function name");

         // just skip processing the current frame if we can't load the filename or function name.
         // this can happen in python 3.13+ since the f_executable isn't guaranteed to be

