+pub fn print_trace(trace: &StackTrace, include_activity: bool) {
+    let thread_id = trace.format_threadid();
+
+    let status = if include_activity {
+        format!(" ({})", trace.status_str())
+    } else if trace.owns_gil {
+        " (gil)".to_owned()
+    } else {
+        "".to_owned()
+    };
