+
+    struct ThreadLock {
+        tid: Tid
+    }
+
+    impl ThreadLock {
+        fn new(tid: Tid) -> Result<ThreadLock, nix::Error> {
+            ptrace::attach(tid)?;
+            wait::waitpid(tid, Some(wait::WaitPidFlag::WSTOPPED))?;
+            debug!("attached to thread {}", tid);
+            Ok(ThreadLock{tid})
+        }
+
+    }
+
+    impl Drop for ThreadLock {
+        fn drop(&mut self) {
+            if let Err(e) = ptrace::detach(self.tid) {
