+            }
+            debug!("detached from thread {}", self.tid);
+        }
+    }
+
+    fn threads(process: &ProcessHandle) -> Result<Vec<i32>, std::io::Error> {
+        let mut ret = Vec::new();
+        let path = format!("/proc/{}/task", process);
+        let tasks = std::fs::read_dir(path)?;
+        for entry in tasks {
